4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(new Set(nextGeneration(block).map(c => c.join(",")))).toEqual(
17	      new Set(block.map(c => c.join(",")))
18	    );
19	  });
20	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — [(0,2),(1,2),(0,1)] includes (1,1) in next gen", () => {
21	    const input: Array<[number, number]> = [[0, 2], [1, 2], [0, 1]];
22	    const result = nextGeneration(input);
23	    const keys = new Set(result.map(c => c.join(",")));
24	    expect(keys).toEqual(new Set(["0,2", "1,2", "0,1", "1,1"]));
25	  });
26	  it("live cell with more than 3 neighbors dies (overpopulation) — center of filled 3x3 dies", () => {
27	    const filled: Array<[number, number]> = [
28	      [0, 0], [1, 0], [2, 0],
29	      [0, 1], [1, 1], [2, 1],
30	      [0, 2], [1, 2], [2, 2],
31	    ];
32	    const keys = new Set(nextGeneration(filled).map(c => c.join(",")));
33	    expect(keys.has("1,1")).toBe(false);
34	  });
35	  it("blinker oscillates vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
36	    const vertical: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
37	    const keys = new Set(nextGeneration(vertical).map(c => c.join(",")));
38	    expect(keys).toEqual(new Set(["-1,1", "0,1", "1,1"]));
39	  });
40	  it.todo("handles negative coordinates correctly — blinker centered at origin works with negative x");
41	});
